#!/usr/bin/env bash
# agentic.sh — Agentic Protocol CLI for B2B 大客户销售.
# Auto-generated by cli_writer.py. Source: synthesis.md Section 9.
set -euo pipefail
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
# shellcheck source=../lib/common.sh
source "${SCRIPT_DIR}/../lib/common.sh"

INDUSTRY="B2B 大客户销售"
DIM_COUNT=6

usage() {
  cat <<EOF
agentic.sh — Agentic Protocol CLI for ${INDUSTRY}

拿到 ${INDUSTRY} 行业的新问题时，按 ${DIM_COUNT} 个研究维度做功课再答。
不直接给答案，而是引导你用资深从业者的研究维度收集信息。

USAGE:
  ./agentic.sh                # interactive walkthrough
  ./agentic.sh --dry-run      # walk through but skip file write
  ./agentic.sh --json         # emit JSON to stdout
  ./agentic.sh --explain      # show backing mental models + sources
  ./agentic.sh --help         # this message
EOF
}

explain() {
  cat <<'EOT'
这个 Agentic Protocol 把这一行人面对新问题的研究维度结构化。

研究维度 (6 个):
  9.1 Deal 健康盘点(MEDDPICC 缺口)
  9.2 买方委员会地图(multithread 状态)
  9.3 方法论流派定位(语境适配)
  9.4 不决策风险评估(status quo / FOMU)
  9.5 合规与采购路径预检(geo + paper process)
  9.6 工具与时效双时钟检查(artifact vs SaaS)

背后的心智模型:
  • 问 ⇄ 教 ⇄ 筛:三派第一性张力,资深人按层混用: 复杂销售的方法论分三派——诊断式提问(SPIN/Gap:「客户有答案,问到痛点不可否认为止」)⇄ 挑战式教学(Challenger:「客户对自己问题的认知是错的,用商业洞见 reframe」)⇄ 资格
  • 头号对手是「不决策」,不是竞品: 预测内丢单的最大去向不是输给对手,而是客户「什么都不做」——维持现状;且一旦购买意向形成,买方更怕「搞砸」(FOMU)而非「错过」(FOMO),所以晚期停滞要按「犹豫」处理(去风险),不是按「异议」处
  • 买方是一个委员会:multithread,否则死于单点故障: 企业采购的决策单位不是「the decision maker」单数,而是一个买方委员会(HBR/Gartner 方向性调查:约 6-10 人,随单子规模上浮)——单线程依赖一个联系人 = 把整单押在一

来源: synthesis.md Section 9 + Section 1.
EOT
}

DRY_RUN=0; JSON=0
for arg in "$@"; do
  case "$arg" in
    --help|-h) usage; exit 0 ;;
    --explain) explain; exit 0 ;;
    --dry-run) DRY_RUN=1 ;;
    --json) JSON=1 ;;
  esac
done

declare -a DIM_TITLES=(
  "Deal 健康盘点(MEDDPICC 缺口)"
  "买方委员会地图(multithread 状态)"
  "方法论流派定位(语境适配)"
  "不决策风险评估(status quo / FOMU)"
  "合规与采购路径预检(geo + paper process)"
  "工具与时效双时钟检查(artifact vs SaaS)"
)
declare -a DIM_QUESTIONS=(
  "八字段能否说出名字——Metrics 量化了吗 / EB 是谁见没见 / Decision Criteria & Process 写下来没 / Paper process 走查没 / Pain 是客户口中的数字吗 / Champion 测试过吗 / 竞争(含 no-decision)定位了吗。"
  "已触达干系人数与角色覆盖(economic/user/technical + coach);谁是 Mobilizer 谁是 Blocker;有没有通向 EB 的路径;单点故障在哪。"
  "对话者/团队的术语暗示其流派语境(说 SPICED = WbD 系,说 pain funnel = Sandler 系,说 commercial insight = Challenger 系);当前任务缺的是哪一层(筛/挖/教/说/谈)。"
  "critical event 是真日期还是愿望;客户「想动但不敢」的信号(重复要材料、加评估项、推迟拍板);现状的既得利益者是谁。"
  "outbound 触达按目标地域适用哪部法(美国电话 TCPA 同意现状/EU 邮件 GDPR-PECR legitimate interest/加拿大 CASL opt-in);买方采购的标准闸(SOC 2 Type II/security 问卷/DPA/法务 redlines 周期)。"
  "任务该落在慢时钟 artifact(scorecard/Blue Sheet/MAP/价值框架——直接用)还是快时钟 SaaS 层(选型/续约——先查 vendor 现状);涉 AI 工具先问「放大的动作人工做时成立吗」。"
)
declare -a DIM_SOURCES=(
  "CRM 记录 + 通话纪要(Gong 类);字段定义对照 meddicc.com / Force Management 的 MEDDIC vs MEDDPICC 页。"
  "通话参与者记录、邮件 thread 抄送结构、LinkedIn 组织架构、challengerinc.com 的 Mobilizer/Talker/Blocker profiles。"
  "各 originator 一手站(huthwaiteinternational/challengerinc/meddicc/sandler/winningbydesign/forcemanagement/blackswanltd)。"
  "JOLT 框架页(jolteffect.com/challengerinc.com 犹豫页);deal 时间线里的停滞模式;Gong 通话里的风险语言。"
  "ftc.gov(CAN-SPAM)/ fcc.gov(TCPA 现行规则与判例动态)/ ico.org.uk(PECR)/ crtc.gc.ca(CASL);客户的 vendor onboarding 文档与采购政策。"
  "\`references/research/02-tools.md\` 决策树与新兴层卡片;vendor newsroom(并购/end-of-sale 公告);Gong Labs 年度数据。"
)
declare -a DIM_OUTPUT_FORMATS=(
  "缺口清单(字段→证据状态→补证动作),附 qualify/disqualify 建议一句话。"
  "干系人矩阵(姓名→角色→温度→最近触点)+ 「下一个该触达的人 + 借谁的手」。"
  "「你在 X 派语境,这个任务该调用 Y 层 + Z 框架」的组合建议,附该框架的已知批判一句话(防银弹化)。"
  "犹豫类型判定(估值问题/信息过载/结果恐惧)+ 对应 JOLT 动作(给推荐/限选项/去风险条款)。"
  "合规 checklist(渠道→地域→当前规则→动作)+ paper process 预案(步骤→负责人→典型时长),标注「TCPA 类条目须复核至今日判例」。"
  "选型/使用建议 + decay 警告(「此结论基于 2026-06 工具格局,SaaS 层 6 个月后须复查」)。"
)
declare -a DIM_FINDINGS=()

if [[ $JSON -eq 0 ]]; then
  ms_section "${INDUSTRY} · Agentic Protocol"
  ms_info "拿到的问题是什么? (输入完后，敲一个空行结束)"
  echo
fi

PROBLEM="$(ms_read_multiline)"
ms_buffer_append "# ${INDUSTRY} — Agentic Protocol Report"
ms_buffer_append ""
ms_buffer_append "_生成时间: $(date '+%Y-%m-%d %H:%M:%S')_"
ms_buffer_append ""
ms_buffer_append "## 问题"
ms_buffer_append ""
ms_buffer_append "$PROBLEM"
ms_buffer_append ""

for i in "${!DIM_TITLES[@]}"; do
  if [[ $JSON -eq 0 ]]; then
    ms_section "${DIM_TITLES[$i]}"
    echo "看什么:    ${DIM_QUESTIONS[$i]}"
    echo "在哪看:    ${DIM_SOURCES[$i]}"
    echo "输出格式:  ${DIM_OUTPUT_FORMATS[$i]}"
    echo
    ms_prompt "你的发现 / 推断 (空行结束):"
    echo
  fi
  finding="$(ms_read_multiline)"
  DIM_FINDINGS+=("$finding")

  ms_buffer_append "## ${DIM_TITLES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**看什么**: ${DIM_QUESTIONS[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**在哪看**: ${DIM_SOURCES[$i]}"
  ms_buffer_append ""
  ms_buffer_append "**发现**:"
  ms_buffer_append ""
  ms_buffer_append "$finding"
  ms_buffer_append ""
done

if [[ $JSON -eq 1 ]]; then
  args=("problem" "$PROBLEM")
  for i in "${!DIM_TITLES[@]}"; do
    args+=("dim_${i}_title" "${DIM_TITLES[$i]}")
    args+=("dim_${i}_finding" "${DIM_FINDINGS[$i]}")
  done
  ms_emit_json "${args[@]}"
elif [[ $DRY_RUN -eq 1 ]]; then
  ms_emit_md_stdout
else
  ms_emit_md_file "agentic-protocol"
fi
